// Description: Collects HTTP response rates and error counts from the Nexus metrics data API.
// Description: Tries the 3.81+ endpoint path first, then falls back to the pre-3.81 path.
import groovy.json.JsonSlurper
import javax.net.ssl.*
import java.security.cert.X509Certificate

def host = hostProps.get("nexus.host")
def user = hostProps.get("nexus.user")
def pass = hostProps.get("nexus.pass")
def port = hostProps.get("nexus.port") ?: "8081"
def useSsl = (hostProps.get("nexus.ssl") ?: "true").toLowerCase() == "true"

def results = [
    "response_2xx_rate": 0,
    "response_4xx_rate": 0,
    "response_5xx_rate": 0,
    "response_4xx_count": 0,
    "response_5xx_count": 0,
    "total_request_rate": 0
]

if (!host || !user || !pass) {
    results.each { k, v -> println("${k}:${v}") }
    return 0
}

def credentials = "${user}:${pass}".bytes.encodeBase64().toString()

def trustAllCerts = [
    checkClientTrusted: { chain, authType -> },
    checkServerTrusted: { chain, authType -> },
    getAcceptedIssuers: { null }
] as X509TrustManager

def sc = SSLContext.getInstance("TLS")
sc.init(null, [trustAllCerts] as TrustManager[], null)
HttpsURLConnection.setDefaultSSLSocketFactory(sc.getSocketFactory())
HttpsURLConnection.setDefaultHostnameVerifier({ hostname, session -> true } as HostnameVerifier)

def proto = useSsl ? "https" : "http"
def baseUrl = "${proto}://${host}:${port}"

def nexusGet(String path, String baseUrl, String credentials) {
    try {
        def url = new URL("${baseUrl}${path}")
        def conn = url.openConnection()
        conn.setRequestProperty("Authorization", "Basic ${credentials}")
        conn.setRequestProperty("Accept", "application/json")
        conn.setConnectTimeout(30000)
        conn.setReadTimeout(30000)
        if (conn.responseCode == 200) {
            return new JsonSlurper().parseText(conn.inputStream.text)
        }
    } catch (Exception e) {
        System.err.println("Nexus API error for ${path}: ${e.message}")
    }
    return null
}

// Try 3.81+ path first, then pre-3.81 fallback
def metricsData = nexusGet("/service/rest/metrics/data", baseUrl, credentials)
if (metricsData == null) {
    metricsData = nexusGet("/service/metrics/data", baseUrl, credentials)
}

if (metricsData != null) {
    def meters = metricsData.meters
    def prefix = "org.eclipse.jetty.webapp.WebAppContext."
    if (meters) {
        // HTTP response rates by status class (Jetty Dropwizard meter names)
        def resp2xx = meters["${prefix}2xx-responses"]
        if (resp2xx) results["response_2xx_rate"] = (resp2xx.m1_rate ?: 0).round(4)

        def resp4xx = meters["${prefix}4xx-responses"]
        if (resp4xx) {
            results["response_4xx_rate"] = (resp4xx.m1_rate ?: 0).round(4)
            results["response_4xx_count"] = resp4xx.count ?: 0
        }

        def resp5xx = meters["${prefix}5xx-responses"]
        if (resp5xx) {
            results["response_5xx_rate"] = (resp5xx.m1_rate ?: 0).round(4)
            results["response_5xx_count"] = resp5xx.count ?: 0
        }
    }

    // Total request rate from the aggregate requests timer
    def timers = metricsData.timers
    if (timers) {
        def reqTimer = timers["${prefix}requests"]
        if (reqTimer) {
            results["total_request_rate"] = (reqTimer.m1_rate ?: 0).round(4)
        }
    }
}

results.each { k, v -> println("${k}:${v}") }
return 0
